import { withSupabaseHandler } from "../../utils/withSupabaseHandler.ts";
import { getGameDetails } from "../../../../../lib/games/get_game_details.js";

export default withSupabaseHandler(async (req, supabase) => {
  try {
    const { gameId } = await req.json();
    if (!gameId) {
      return new Response(JSON.stringify({ error: "Missing gameId" }), { status: 400 });
    }

    const result = await getGameDetails(supabase, gameId);
    return new Response(JSON.stringify(result), { status: 200 });
  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), { status: 400 });
  }
});
